1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	export function processScenario(scenario: any): any {
12	  const step = scenario.steps[0];
13	  if (step.items.length === 0) {
14	    return { results: [{ premium: PROCESSING_FEE }] };
15	  }
16	  const item = step.items[0];
17	  const basePremium = BASE_PREMIUM[item.type];
18	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
19	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
20	  return { results: [{ premium }] };
21	}
